/**
 * Learning path definitions for the language section.
 *
 * Each path determines which items are included, how many levels exist,
 * and the pacing of content introduction (kana, vocab, grammar, sentences).
 *
 * Path JSON files generated by `scripts/build-language-levels.mjs` contain
 * the actual item-to-level assignments for each path.
 */

export type PathId = "n5" | "conversational" | "n1" | "completionist";

export interface PathPacing {
	/** Number of levels dedicated primarily to kana learning */
	kanaLevels: number;
	/** [min, max] vocabulary items per level (target, not hard limit) */
	vocabDensity: [number, number];
	/** First level where grammar items appear */
	grammarIntroLevel: number;
	/** First level where conjugation items appear */
	conjugationIntroLevel: number;
	/** First level where sentence items appear */
	sentenceIntroLevel: number;
}

export interface LearningPath {
	id: PathId;
	label: string;
	description: string;
	/** Which JLPT levels are included (e.g., ["N5"], ["N5","N4","N3"]) */
	jlptScope: string[];
	/** Total number of levels in this path */
	maxCoreLevels: number;
	/** If set, only include vocab with frequency_rank <= this value */
	frequencyCutoff?: number;
	/** Whether to include items without a JLPT tag */
	includeUntagged: boolean;
	/** Per-path pacing configuration */
	pacing: PathPacing;
}

