export const PATH_IDS: PathId[] = [
	"n5",
	"conversational",
	"n1",
	"completionist",
];

export const DEFAULT_PATH: PathId = "n5";

export function getPath(id: PathId): LearningPath {
	return LEARNING_PATHS[id];
}
